mapper.sql:
from aiw_ai_model m
where 1 = 1

    and m.model_code = #{criteria.modelCode}


    and m.model_type = #{criteria.modelType}


    and m.provider = #{criteria.provider}


    and m.status = #{criteria.status}

mapper.select:
select *
from aiw_ai_model
where model_code = #{modelCode} and model_version = #{modelVersion}

select m.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
